  s.addText('│                  │', {
    x: 5.5, y: 3.7, w: 4, h: 0.5,
    fontSize: 14, color: color, align: 'center', fill: { color: color }
  });
  s.addText('└──────────────────┘', {
    x: 5.5, y: 4.1, w: 4, h: 0.5,
    fontSize: 14, color: color, align: 'center', fill: { color: color }
  });

  s.addText('联系方式', {
    x: 5.7, y: 2.65, w: 3.6, h: 0.4,
    fontSize: 18, color: colors.white, bold: true,
